-- 0207_real_cdmx_alcaldias.sql
-- Replace the 7 synthetic AGEM boxes (seed/10_geo.sql ST_MakeEnvelope fixtures) with the REAL
-- boundaries of all 16 CDMX alcaldías (CONABIO 2023, INEGI CVE_MUN-coded), and rebind every
-- current observation by point-in-polygon. The boxes only covered ~71k of 183k visible potholes;
-- real, gap-free polygons bind essentially all of them so the region filter and the natural-
-- language agent see the whole city. Geometry is Douglas-Peucker simplified to ~90 m (ample for
-- binning points) to keep the migration compact. The 7 prior alcaldías keep their deterministic
-- ids (upsert updates geometry in place); Milpa Alta (009) gets an 'a9...' id to avoid colliding
-- with the AGEE state area id. Idempotent.

insert into geo.geo_areas
  (id, edition_id, level, source_cvegeo, cve_ent, cve_mun, name, parent_area_id, geometry)
