on conflict (id) do update set
  geometry = excluded.geometry,
  name = excluded.name,
  source_cvegeo = excluded.source_cvegeo,
  cve_mun = excluded.cve_mun,
  cve_ent = excluded.cve_ent,
  parent_area_id = excluded.parent_area_id;

-- Rebind every CURRENT observation to the alcaldía whose REAL polygon contains it.
delete from geo.observation_geo_bindings b
using vision.observations o
where b.observation_id = o.id
  and b.edition_id = 'ed000000-0000-0000-0000-000000000001'
  and o.superseded_by_observation_id is null
  and o.resolved_at is null;

insert into geo.observation_geo_bindings
  (observation_id, edition_id, agee_area_id, agem_area_id, bound_at)
select distinct on (o.id)
  o.id, 'ed000000-0000-0000-0000-000000000001'::uuid, '9e000000-0000-0000-0000-000000000009'::uuid, agem.id, now()
from vision.observations o
join geo.geo_areas agem
  on agem.edition_id = 'ed000000-0000-0000-0000-000000000001'
 and agem.level = 'AGEM'
 and ST_Contains(agem.geometry, o.location::geometry)
where o.superseded_by_observation_id is null
  and o.resolved_at is null
order by o.id, agem.cve_mun
on conflict (observation_id, edition_id) do nothing;
